    11→type SqrcUserTopicProgressRepository struct {
    12→	sqrc db.Querier
    13→}
    14→
    15→func NewSqrcUserTopicProgressRepository(q db.Querier) *SqrcUserTopicProgressRepository {
    16→	return &SqrcUserTopicProgressRepository{sqrc: q}
    17→}
    18→
    19→func (repository *SqrcUserTopicProgressRepository) getProgress(ctx context.Context, userId string, courseId string) (Progress, error) {
    20→	var userIdUuid, courseIdUuid pgtype.UUID
    21→
    22→	if err := userIdUuid.Scan(userId); err != nil {
    23→		return Progress{}, err
    24→	}
    25→	if err := courseIdUuid.Scan(courseId); err != nil {
    26→		return Progress{}, err
    27→	}
    28→
    29→	rows, err := repository.sqrc.GetProgressByUserIdAndCourseId(ctx, db.GetProgressByUserIdAndCourseIdParams{
    30→		Userid:   userIdUuid,
    31→		Courseid: courseIdUuid,
    32→	})
    33→	if err != nil {
    34→		return Progress{}, err
    35→	}
    36→
    37→	records := make([]ProgressRecord, len(rows))
    38→	for i, row := range rows {
    39→		records[i] = ProgressRecord{
    40→			userTopicProgressId:  row.UserTopicProgressID.String(),
    41→			courseSectionId:      row.CourseSectionID.String(),
    42→			courseSectionTopicId: row.CourseSectionTopicID.String(),
    43→			sectionNumber:        int(row.SectionIndex),
    44→			topicNumber:          int(row.TopicIndex),
    45→			status:               row.Status,
    46→		}
    47→	}
    48→
    49→	return Progress{courseId: courseId, userId: userId, records: records}, nil
    50→}
    51→
    52→func (repository *SqrcUserTopicProgressRepository) save(ctx context.Context, progress *Progress) error {
    53→	for _, record := range progress.records {
    54→		progressIdUuid, err := generateUUID()
    55→		if err != nil {
    56→			return err
    57→		}
    58→		if record.userTopicProgressId != "" {
    59→			if err := progressIdUuid.Scan(record.userTopicProgressId); err != nil {
    60→				return err
    61→			}
    62→		}
    63→
    64→		var courseIdUuid, sectionIdUuid, topicIdUuid, userIdUuid pgtype.UUID
    65→		if err := courseIdUuid.Scan(progress.courseId); err != nil {
    66→			return err
    67→		}
    68→		if err := sectionIdUuid.Scan(record.courseSectionId); err != nil {
    69→			return err
    70→		}
    71→		if err := topicIdUuid.Scan(record.courseSectionTopicId); err != nil {
    72→			return err
    73→		}
    74→		if err := userIdUuid.Scan(progress.userId); err != nil {
    75→			return err
    76→		}
    77→
    78→		if err := repository.sqrc.UpsertProgress(ctx, db.UpsertProgressParams{
    79→			Usertopicprogressid:  progressIdUuid,
    80→			Courseid:             courseIdUuid,
    81→			Coursesectionid:      sectionIdUuid,
    82→			Coursesectiontopicid: topicIdUuid,
    83→			Userid:               userIdUuid,
    84→			Status:               record.status,
    85→		}); err != nil {
    86→			return err
    87→		}
    88→	}
    89→	return nil
    90→}
    91→
    92→func generateUUID() (pgtype.UUID, error) {
    93→	var u pgtype.UUID
    94→	_, err := rand.Read(u.Bytes[:])
    95→	if err != nil {
    96→		return pgtype.UUID{}, err
    97→	}
    98→	u.Bytes[6] = (u.Bytes[6] & 0x0f) | 0x40
    99→	u.Bytes[8] = (u.Bytes[8] & 0x3f) | 0x80
   100→	u.Valid = true
   101→	return u, nil
   102→}
