    75→func (p *Progress) lastTopicPosition() ProgressPosition {
    76→	pos := ProgressPosition{sectionNumber: -1, topicNumber: -1, status: "NOT_STARTED"}
    77→
    78→	for _, record := range p.records {
    79→		if record.sectionNumber > pos.sectionNumber || (record.sectionNumber == pos.sectionNumber && record.topicNumber > pos.topicNumber) {
    80→			pos = ProgressPosition{sectionNumber: record.sectionNumber, topicNumber: record.topicNumber, status: record.status}
    81→		}
    82→	}
    83→
    84→	return pos
    85→}
    86→
    87→func (p *Progress) start(section Section, topic Topic) string {
    88→	for _, record := range p.records {
    89→		if record.courseSectionTopicId == topic.topicId && record.courseSectionId == section.sectionId {
    90→			return topic.topicId
    91→		}
    92→	}
    93→
    94→	p.records = append(p.records, ProgressRecord{
    95→		courseSectionId:      section.sectionId,
    96→		courseSectionTopicId: topic.topicId,
    97→		sectionNumber:        section.number,
    98→		topicNumber:          topic.number,
    99→		status:               "IN_PROGRESS",
   100→		startedAt:            time.Now().Format(time.RFC3339),
   101→		completedAt:          nil,
   102→	})
   103→	return topic.topicId
   104→}
