   106→var ErrEnrollmentNumberIsNotFound = errors.New("enrollment number is not found")
   107→var ErrEnrollmentNotAllowed = errors.New("enrollment not allowed")
   108→
   109→func (course *Course) checkEnrollable(userId string) error {
   110→	if course.publishStatus != "published" && course.author.authorId != userId {
   111→		return ErrEnrollmentNotAllowed
   112→	}
   113→	return nil
   114→}
