   116→func (course *Course) findTopicToStart(sectionNumber *int, topicNumber *int, lastPosition ProgressPosition) (Section, Topic, error) {
   117→	var secNum, topNum int
   118→
   119→	if sectionNumber != nil {
   120→		secNum = *sectionNumber
   121→		if topicNumber != nil {
   122→			topNum = *topicNumber
   123→		}
   124→	} else {
   125→		switch lastPosition.status {
   126→		case "COMPLETED":
   127→			nextPosition, err := course.nextTopic(TopicPosition{sectionNumber: lastPosition.sectionNumber, topicNumber: lastPosition.topicNumber})
   128→			if err != nil {
   129→				return Section{}, Topic{}, ErrEnrollmentNumberIsNotFound
   130→			}
   131→			secNum, topNum = nextPosition.sectionNumber, nextPosition.topicNumber
   132→		case "IN_PROGRESS":
   133→			secNum = lastPosition.sectionNumber
   134→			topNum = lastPosition.topicNumber
   135→		default:
   136→			secNum = 0
   137→			topNum = 0
   138→		}
   139→	}
   140→
   141→	section, topic, err := course.getTopic(secNum, topNum)
   142→	if err != nil {
   143→		return Section{}, Topic{}, ErrEnrollmentNumberIsNotFound
   144→	}
   145→	return section, topic, nil
   146→}
   147→
   148→type TopicPosition struct {
   149→	sectionNumber int
   150→	topicNumber   int
   151→}
   152→
   153→var ErrTopicPositionOutOfRange = errors.New("topic position is out of range")
   154→
   155→func (course *Course) getTopic(sectionNumber int, topicNumber int) (Section, Topic, error) {
   156→	if sectionNumber < 0 || sectionNumber >= len(course.sections) {
   157→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   158→	}
   159→	section := course.sections[sectionNumber]
   160→	if topicNumber < 0 || topicNumber >= len(section.topics) {
   161→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   162→	}
   163→	return section, section.topics[topicNumber], nil
   164→}
   165→
   166→func (course *Course) nextTopic(currentTopicPosition TopicPosition) (topicPosition TopicPosition, err error) {
   167→	if currentTopicPosition.sectionNumber < 0 || currentTopicPosition.sectionNumber >= len(course.sections) {
   168→		return TopicPosition{}, ErrTopicPositionOutOfRange
   169→	}
   170→
   171→	section := course.sections[currentTopicPosition.sectionNumber]
   172→	if currentTopicPosition.topicNumber < 0 || currentTopicPosition.topicNumber >= len(section.topics) {
   173→		return TopicPosition{}, ErrTopicPositionOutOfRange
   174→	}
   175→
   176→	if currentTopicPosition.topicNumber == len(section.topics)-1 {
   177→		if currentTopicPosition.sectionNumber == len(course.sections)-1 {
   178→			return TopicPosition{}, ErrTopicPositionOutOfRange
   179→		}
   180→		return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber + 1, topicNumber: 0}, nil
   181→	}
   182→
   183→	return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber, topicNumber: currentTopicPosition.topicNumber + 1}, nil
   184→}
