    23→
    24→func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
    25→	return EnrollCourseUsecase{
    26→		courseRepository:   courseRepo,
    27→		progressRepository: progressRepo,
    28→	}
    29→}
    30→
    31→type CourseRepository interface {
    32→	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
    33→}
    34→
    35→type ProgressRepository interface {
    36→	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
    37→	save(ctx context.Context, progress *Progress) error
    38→}
    39→
    40→type EnrollCourseUsecaseInterface interface {
    41→	execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error)
    42→}
    43→
    44→func (usecase EnrollCourseUsecase) execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error) {
    45→	var course Course
    46→	var progress Progress
    47→
    48→	g, gctx := errgroup.WithContext(ctx)
    49→	g.Go(func() error {
    50→		var err error
    51→		course, err = usecase.courseRepository.getCourseByCourseId(gctx, params.courseId)
    52→		return err
    53→	})
    54→	g.Go(func() error {
    55→		var err error
    56→		progress, err = usecase.progressRepository.getProgress(gctx, params.userId, params.courseId)
    57→		return err
    58→	})
    59→	if err := g.Wait(); err != nil {
    60→		return "", err
    61→	}
    62→
    63→	if err := course.checkEnrollable(params.userId); err != nil {
    64→		return "", err
    65→	}
    66→
    67→	if params.sectionNumber == nil && params.topicNumber != nil {
    68→		return "", ErrTopicNumberRequireSectionNumber
    69→	}
    70→
    71→	section, topic, err := course.findTopicToStart(params.sectionNumber, params.topicNumber, progress.lastTopicPosition())
    72→	if err != nil {
    73→		return "", err
    74→	}
    75→
    76→	topicId := progress.start(section, topic)
    77→
    78→	return topicId, usecase.progressRepository.save(ctx, &progress)
    79→}
